return $input.all().map(item => {
  let text = item.json.snippet || "";

  // Remove reply threads
  text = text.split(/On\s.+wrote:/)[0];

  // Clean spaces
  text = text.replace(/\n+/g, " ").trim();

  // Convert timestamp to readable date
  let rawDate = item.json.internalDate;
  let formattedDate = rawDate 
    ? new Date(parseInt(rawDate)).toISOString().split("T")[0]
    : null;

  return {
    json: {    // keep all original data
      cleanText: text,
      emailDate: formattedDate // ✅ formatted date
    }
  };
});

const results = [];

for (const item of $input.all()) {
  const content = item.json.choices?.[0]?.message?.content || "[]";
  let leaves = [];
  try {
    leaves = JSON.parse(content);
  } catch (e) {
    continue;
  }

  // Build ONE flat object with all paths
  const batchData = {};

  leaves.forEach((leave) => {
    const d = new Date(leave.date);
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, "0");
    const value = leave.type === "half" ? 0.5 : 1;
    const path = `leaves/${year}/${month}/${leave.date}`;

    // Each path becomes a key in batch object
    batchData[path] = {
      type: leave.type,
      value: value,
    };
  });

  results.push({
    json: {
      batchData  // single object with all paths
    }
  });
}

return results;
